var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"저는 아합이라고 합니다.","JPN":"私はアハブと申します。","ENG":"I am Ahab.","TWN":"我是亞哈。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"전설 속의 침식체를 사냥하기 위해 토벌대를 조직했죠.","JPN":"伝説の侵食体を仕留めるために、討伐隊を立ち上げたんです。","ENG":"I have assembled an extermination team to hunt the legendary C.O.","TWN":"我有組織一個專門討伐傳說中侵蝕體的討伐隊。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"한 번이라도 마주쳐서 싸워보신 분이라면 큰 도움이 될 것이라 생각합니다.","JPN":"伝説の浸食体と戦った経験のある方なら、とても心強い。","ENG":"I believe that you will be of great help to us as you have fought this C.O. yourself.","TWN":"既然你曾經跟它交手過，我相信對我們會很有幫助。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"저희 토벌대와 함께해 주실 수 있습니까?","JPN":"ぜひ、私たちにご協力いただけませんか？","ENG":"Could you come with us?","TWN":"可以請你加入我們討伐隊嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"전설 속의 침식체…….","JPN":"伝説の侵食体……","ENG":"The legendary C.O...","TWN":"傳說中的侵蝕體……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"강한 카운터들을 고용하려면 비싼 값이 들거든요. 그래서…… 저도 모르게…….","JPN":"強いカウンターを雇うには、費用がかかるので、それで……つい……","ENG":"It's expensive to hire a strong Counter like yourself. So... without thinking–","TWN":"因為雇用厲害的制裁者要花很多錢，所以…我才不自覺地……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"카운터를 고용한다고? 무슨 헛소리지?","JPN":"カウンターを雇う？　いったい何を言っているのだ？","ENG":"Hire Counters? What are you talking about?","TWN":"雇用制裁者？你在說什麼？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"강한 카운터를 고용하려면 값이 만만치 않을 거다.","JPN":"強いカウンターを雇うには、相当な金が必要になるぞ。","ENG":"Hiring a strong Counter will cost you.","TWN":"要雇用厲害的制裁者可不便宜。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그만한 비용은 감당할 수 있는 거겠지?","JPN":"それを賄える資金力はあるのか？","ENG":"Can you afford that cost?","TWN":"你付得起這個錢嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"특히나…… 그 고래 녀석과 싸워서 살아남은 카운터는 더더욱 비쌀 테고.","JPN":"特に……あのクジラと戦って生き延びた経験を持つカウンターは、より高額だ。","ENG":"It will be much more expensive... especially if she is someone who fought and survived an encounter with that whale.","TWN":"尤其是……和那頭鯨魚交手後還能活下來的制裁者，費用會更高喔。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"물론입니다.","JPN":"もちろんです。","ENG":"Of course.","TWN":"沒問題！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그 침식체를 잡아만 주신다면 기여도에 따라 막대한 보상을 드릴 계획입니다.","JPN":"あの侵食体さえ仕留めてくだされば、貢献度に基づいて報酬を出させていただきます。","ENG":"I will give you a massive reward based on your contribution if you defeat that C.O.","TWN":"只要能逮到那個侵蝕體，我們會根據你的貢獻度給予豐富的獎勵。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"아주 고품질의 이터니움을 포함해서 말이죠.","JPN":"極めて高品質なエタニウムもご提供しましょう。","ENG":"Along with some high-quality Eternium as well.","TWN":"非常高品質的永恆之金也包含在內。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"내가 필요한 건 그런 일확천금의 보물들이 아니야.","JPN":"私が求めているのは、そんな懸賞金のようなものではない。","ENG":"What I want are not riches and wealth.","TWN":"我想要的不是財富。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……고래의 목숨.","JPN":"……クジラの命。","ENG":"...The whale's life.","TWN":"……那隻鯨魚的命。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그 빌어먹을 고래를 내 손으로 죽일 수만 있다면 다른 건 어떻게 되든 상관없어.","JPN":"あの忌々しいクジラをこの手で殺れるなら、それ以外何もいらない。","ENG":"If I can kill that whale with my hands, I don't care about the rest.","TWN":"只要能親手殺那隻該死的鯨魚，其他的我都不在乎。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"하하. 깊은 원한이 느껴지는군요. 좋습니다.","JPN":"はは、ものすごい怨念ですね。わかりました。","ENG":"Haha. I sense deep resentment. Very well.","TWN":"哈哈，有感受的濃濃的恨意。沒問題！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그러고 보니 토벌대를 조직했다고 했지?","JPN":"討伐隊を作ったと言っていたな？","ENG":"You said you assembled an extermination team, correct?","TWN":"然後，你剛說你有組織一個討伐隊是嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"내가 듣기론 이곳 용병들은 거칠고, 안하무인이라고 들었는데, 전설 따위에 쉽게 넘어왔군.","JPN":"私が聞いた情報によると、ここの傭兵は気性が粗い上、あまり協調的ではないそうだ。そんな連中をよく引き入れたな。","ENG":"What I've heard about these mercenaries is that they are both arrogant and merciless. Still, it appears as though the mere mention of the word \\"legend\\" prompted them to jump on.","TWN":"我聽說這裡的傭兵粗魯又目中無人，竟然如此輕易聽信傳言。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"생각보다 어렵진 않았습니다.","JPN":"そんなに難しくはありませんでした。","ENG":"It wasn't as difficult as you think.","TWN":"原因其實比你想的還要簡單。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"로터스에 이 정도의 고밀도 침식파가 섞인 모래 폭풍은 이례적입니다.","JPN":"ロータスでこれほど高密度な侵食波が混じった砂嵐が訪れるのは、異例なことです。","ENG":"A sandstorm with high-density Corruption rays is unusual even for Lotus.","TWN":"在洛德斯，這種挾帶高密度侵蝕波的沙塵暴非常罕見。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"따라서 로터스 관리국은 이 모래 폭풍이 어떤 이면세계로부터 불어오는 것으로 판단하고 있죠.","JPN":"ロータス管理局は、今回の砂嵐は裏世界から吹いてきているものだと判断しました。","ENG":"Thus, the Lotus City Management has deemed that this sandstorm is from the Counterside.","TWN":"因此洛德斯管理局判斷，這場沙塵暴是從某個異界吹來的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"이런 현상은 과거, 20년 전에도 한 번 발생했던 적이 있습니다.","JPN":"このような現象は、20年前にも一度発生したことがあります。","ENG":"There was only one other instance of this phenomenon, and it was twenty years ago.","TWN":"這種現象在20年前也曾發生過一次。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"바로 에리두가 사라지던 날이죠.","JPN":"それは、エリドゥが消滅した日です。","ENG":"The day Eridu disappeared.","TWN":"正是埃里都消失的那一天。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"에리두…….","JPN":"エリドゥ……","ENG":"Eridu...","TWN":"埃里都……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"네, 이는 분명 에리두를 삼킨 침식체가 나타났다는 증거라고 생각했습니다.","JPN":"はい、今の状況は、エリドゥを飲み込んだ侵食体の出現を裏付けるものであると判断しました。","ENG":"Yes. I believe that this was proof that the C.O. that swallowed Eridu has reappeared.","TWN":"沒錯，我認為這就是吞噬掉埃里都的侵蝕體再次現身的證據。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그렇기에 다른 용병단들도 제 말을 믿고 토벌대를 조직하기로 한 거죠.","JPN":"傭兵団もそれを知っており、討伐隊の立ち上げに際して、説得するのに苦労は強いられませんでしたね。","ENG":"That is how I was able to make the other mercenaries follow me and form an extermination team.","TWN":"所以其他傭兵團也相信我的話，決定組織討伐隊。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"하지만 그 침식체는 어중이떠중이들로는 쉽게 정화할 수 없다.","JPN":"だが、あの侵食体は有象無象を集めたところで、簡単に勝てる相手ではない。","ENG":"But that C.O. can't be purified with ordinary mercenaries.","TWN":"但那個侵蝕體不是隨便什麼人就能淨化的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아무리 토벌대의 숫자가 많더라도, 침식체를 잡을 만한 무기가 없다면 무용지물일 터.","JPN":"いくら討伐隊の人数をたくさん揃えたところで、侵食体用の武器がなければ無意味だろう。","ENG":"No matter how many mercenaries you've gathered, it will be useless unless you have the proper weapon to kill it.","TWN":"就算討伐隊人數再多，如果沒有能殺死它的武器，也是英雄無用武之處的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"토벌대가 조직될 만큼 믿을 만한 수단이 너에게 있다는 소리인가?","JPN":"討伐隊の士気を上げ、戦いに向かわせる確実な方法が、君にはあるというのか？","ENG":"Which leads me to believe that you have something that made you credible enough to form such a team.","TWN":"你要怎麼說服我這個討伐隊有足夠的能力？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"과연, 뛰어난 안목이십니다.","JPN":"なるほど、さすが鋭いですね。","ENG":"I see you have a keen eye.","TWN":"果然是觀察精闢。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"로터스의 용병들은 거칠기로 유명하죠.","JPN":"確かに、ロータスの傭兵たちは気性が荒いことで有名です。","ENG":"Lotus' mercenaries are infamous for their recklessness.","TWN":"洛德斯的傭兵可是有名的難搞。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"확실한 증거와 그들을 설득시킬만한 방법을 준비했습니다.","JPN":"確かな証拠と、彼らを説得するための方法は用意済みです。","ENG":"So, I provided undeniable proof to persuade them.","TWN":"我當然有準備充分的證據和說服他們的方法。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"분명 당신도 만족하실 겁니다.","JPN":"きっと、あなたも納得してくれることでしょう。","ENG":"I'm sure you will also be satisfied as well.","TWN":"保證也會讓你滿意的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"토벌대는 숫자에 불과하나, 일단 그 규모를 확인하시는 것도 좋겠습니다.","JPN":"討伐隊はただの数合わせですが、一応どのくらいの規模か、確認してください。","ENG":"Though numbers might not mean much, I suggest you check the team's size first.","TWN":"討伐隊只是個數字沒錯，不過讓你確認一下規模也不錯。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"주변의 날고 기는 용병단들을 모두 끌어모았거든요.","JPN":"周辺の有力な傭兵団を全て引き入れました。","ENG":"I have gathered only the strongest of mercenaries, you see.","TWN":"我可是拉攏了這附近最頂尖的傭兵團呢。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"후후. 수긍한 것으로 알죠.","JPN":"ふふ、ご納得いただけたと判断いたしますね。","ENG":"Haha. I'll take that as a yes, then.","TWN":"呵呵，那我就當你同意囉。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"장소를 알려드릴 테니 그쪽으로 오시면 됩니다.","JPN":"場所をお教えしますので、そちらにいらしてください。","ENG":"I will tell you the location, so please come have a look.","TWN":"我再把地點告訴你，直接約那裡吧。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"좋아. 네 말대로하지. 보고 나서 결정해도 늦지 않을 테니까.","JPN":"いいだろう。最終決断は実際に見てからでも遅くはないからな。","ENG":"Very well. I will do as you say. It won't be too late to decide after seeing it.","TWN":"好，就照你說的。等看完再決定也不遲。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"난 아디트야라고 부르면 된다. 잘 부탁하지. 아합.","JPN":"アーディティヤと呼んでくれ。よろしく頼む。アハブ。","ENG":"You can call me Aditya. Let's see if we can make something work, Ahab.","TWN":"你叫我阿迪亞就好。請多關照，亞哈。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"……아디트야.","JPN":"……アーディティヤ。","ENG":"...Aditya.","TWN":"……阿迪亞。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"알겠습니다. 그럼 기다리고 있죠.","JPN":"かしこまりました。では、お待ちしております。","ENG":"Understood. Then, I'll be waiting for you.","TWN":"好，我會在那裡等你。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"좋아. 준비가 되는 대로 토벌대를 보러 가겠다.","JPN":"ああ、準備が出来次第、討伐隊の確認に向かおう。","ENG":"All right. I'll head to where the extermination team is as soon as I'm ready.","TWN":"好，我準備好就過去。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"가망이 없다고 생각하면 협력은 없었던 일로 할 테니 그렇게 알도록.","JPN":"言っておくが、可能性がないと判断したら、協力するという話はなかったことにする。","ENG":"Just know that I won't be cooperating if I see that it'll be a waste of my time.","TWN":"要是我認為不值得，那就當沒這回事，知道嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};